23	#include "mupdf/fitz.h"
24	
25	#include <assert.h>
26	#include <limits.h>
27	#include <stdio.h>
28	#include <string.h>
29	
30	typedef struct fz_item
31	{
32		void *key;
33		fz_storable *val;
34		size_t size;
35		struct fz_item *next;
36		struct fz_item *prev;
37		fz_store *store;
38		const fz_store_type *type;
39	} fz_item;
40	
41	/* Every entry in fz_store is protected by the alloc lock */
42	struct fz_store
43	{
44		int refs;
45	
46		/* Every item in the store is kept in a doubly linked list, ordered
47		 * by usage (so LRU entries are at the end). */
48		fz_item *head;
49		fz_item *tail;
50	
51		/* We have a hash table that allows to quickly find a subset of the
52		 * entries (those whose keys are indirect objects). */
53		fz_hash_table *hash;
54	
55		/* We keep track of the size of the store, and keep it below max. */
56		size_t max;
57		size_t size;
58	
59		int defer_reap_count;
60		int needs_reaping;
61		int scavenging;
62	};
63	
64	void
65	fz_new_store_context(fz_context *ctx, size_t max)
66	{
67		fz_store *store;
68		store = fz_malloc_struct(ctx, fz_store);
69		fz_try(ctx)
70		{
71			store->hash = fz_new_hash_table(ctx, 4096, sizeof(fz_store_hash), FZ_LOCK_ALLOC, NULL);
72		}
73		fz_catch(ctx)
74		{
75			fz_free(ctx, store);
76			fz_rethrow(ctx);
77		}
78		store->refs = 1;
79		store->head = NULL;
80		store->tail = NULL;
81		store->size = 0;
82		store->max = max;
83		store->defer_reap_count = 0;
84		store->needs_reaping = 0;
85		ctx->store = store;
86	}
87	
88	void *
89	fz_keep_storable(fz_context *ctx, const fz_storable *sc)
90	{
91		/* Explicitly drop const to allow us to use const
92		 * sanely throughout the code. */
93		fz_storable *s = (fz_storable *)sc;
94		if (s)
95			return fz_keep_imp(ctx, s, &s->refs);
96		return NULL;
97	}
98	
99	void *fz_keep_key_storable(fz_context *ctx, const fz_key_storable *sc)
100	{
101		if (sc)
102			return fz_keep_storable(ctx, &sc->storable);
103		return NULL;
104	}
105	
106	/*
107		Entered with FZ_LOCK_ALLOC held.
108		Drops FZ_LOCK_ALLOC.
109	*/
110	static void
111	do_reap(fz_context *ctx)
112	{
113		fz_store *store = ctx->store;
114		fz_item *item, *prev, *remove;
115	
116		if (store == NULL)
117		{
118			fz_unlock(ctx, FZ_LOCK_ALLOC);
119			return;
120		}
121	
122		fz_assert_lock_held(ctx, FZ_LOCK_ALLOC);
123	
124		ctx->store->needs_reaping = 0;
125	
126		FZ_LOG_DUMP_STORE(ctx, "Before reaping store:\n");
127	
128		/* Reap the items */
129		remove = NULL;
130		for (item = store->tail; item; item = prev)
131		{
132			prev = item->prev;
133	
134			if (item->type->needs_reap == NULL || item->type->needs_reap(ctx, item->key) == 0)
135				continue;
136	
137			/* We have to drop it */
138			store->size -= item->size;
139	
140			/* Unlink from the linked list */
141			if (item->next)
142				item->next->prev = item->prev;
143			else
144				store->tail = item->prev;
145			if (item->prev)
146				item->prev->next = item->next;
147			else
148				store->head = item->next;
149	
150			/* Remove from the hash table */
151			if (item->type->make_hash_key)
152			{
153				fz_store_hash hash = { NULL };
154				hash.drop = item->val->drop;
155				if (item->type->make_hash_key(ctx, &hash, item->key))
156					fz_hash_remove(ctx, store->hash, &hash);
157			}
158	
159			/* Store whether to drop this value or not in 'prev' */
160			if (item->val->refs > 0)
161				(void)Memento_dropRef(item->val);
162			item->prev = (item->val->refs > 0 && --item->val->refs == 0) ? item : NULL;
163	
164			/* Store it in our removal chain - just singly linked */
165			item->next = remove;
166			remove = item;
167		}
168		fz_unlock(ctx, FZ_LOCK_ALLOC);
169	
170		/* Now drop the remove chain */
171		for (item = remove; item != NULL; item = remove)
172		{
173			remove = item->next;
174	
175			/* Drop a reference to the value (freeing if required) */
176			if (item->prev)
177				item->val->drop(ctx, item->val);
178	
179			/* Always drops the key and drop the item */
180			item->type->drop_key(ctx, item->key);
181			fz_free(ctx, item);
182		}
183		FZ_LOG_DUMP_STORE(ctx, "After reaping store:\n");
184	}
185	
186	void fz_drop_key_storable(fz_context *ctx, const fz_key_storable *sc)
187	{
188		/* Explicitly drop const to allow us to use const
189		 * sanely throughout the code. */
190		fz_key_storable *s = (fz_key_storable *)sc;
191		int drop;
192		int unlock = 1;
193	
194		if (s == NULL)
195			return;
196	
197		fz_lock(ctx, FZ_LOCK_ALLOC);
198		assert(s->storable.refs != 0);
199		if (s->storable.refs > 0)
200		{
201			(void)Memento_dropRef(s);
202			drop = --s->storable.refs == 0;
203			if (!drop && s->storable.refs == s->store_key_refs)
204			{
205				if (ctx->store->defer_reap_count > 0)
206				{
207					ctx->store->needs_reaping = 1;
208				}
209				else
210				{
211					do_reap(ctx);
212					unlock = 0;
213				}
214			}
215		}
216		else
217			drop = 0;
218		if (unlock)
219			fz_unlock(ctx, FZ_LOCK_ALLOC);
220		/*
221			If we are dropping the last reference to an object, then
222			it cannot possibly be in the store (as the store always
223			keeps a ref to everything in it, and doesn't drop via
224			this method. So we can simply drop the storable object
225			itself without any operations on the fz_store.
226		 */
227		if (drop)
228			s->storable.drop(ctx, &s->storable);
229	}
230	
231	void *fz_keep_key_storable_key(fz_context *ctx, const fz_key_storable *sc)
232	{
233		/* Explicitly drop const to allow us to use const
234		 * sanely throughout the code. */
235		fz_key_storable *s = (fz_key_storable *)sc;
236	
237		if (s == NULL)
238			return NULL;
239	
240		fz_lock(ctx, FZ_LOCK_ALLOC);
241		if (s->storable.refs > 0)
242		{
243			(void)Memento_takeRef(s);
244			++s->storable.refs;
245			++s->store_key_refs;
246		}
247		fz_unlock(ctx, FZ_LOCK_ALLOC);
248		return s;
249	}
250	
251	void fz_drop_key_storable_key(fz_context *ctx, const fz_key_storable *sc)
252	{
253		/* Explicitly drop const to allow us to use const
254		 * sanely throughout the code. */
255		fz_key_storable *s = (fz_key_storable *)sc;
256		int drop;
257	
258		if (s == NULL)
259			return;
260	
261		fz_lock(ctx, FZ_LOCK_ALLOC);
262		assert(s->store_key_refs > 0 && s->storable.refs >= s->store_key_refs);
263		(void)Memento_dropRef(s);
264		drop = --s->storable.refs == 0;
265		--s->store_key_refs;
266		fz_unlock(ctx, FZ_LOCK_ALLOC);
267		/*
268			If we are dropping the last reference to an object, then
269			it cannot possibly be in the store (as the store always
270			keeps a ref to everything in it, and doesn't drop via
271			this method. So we can simply drop the storable object
272			itself without any operations on the fz_store.
273		 */
274		if (drop)
275			s->storable.drop(ctx, &s->storable);
276	}
277	
278	static void
279	evict(fz_context *ctx, fz_item *item)
280	{
281		fz_store *store = ctx->store;
282		int drop;
283	
284		store->size -= item->size;
285		/* Unlink from the linked list */
286		if (item->next)
287			item->next->prev = item->prev;
288		else
289			store->tail = item->prev;
290		if (item->prev)
291			item->prev->next = item->next;
292		else
293			store->head = item->next;
294	
295		/* Drop a reference to the value (freeing if required) */
296		if (item->val->refs > 0)
297			(void)Memento_dropRef(item->val);
298		drop = (item->val->refs > 0 && --item->val->refs == 0);
299	
300		/* Remove from the hash table */
301		if (item->type->make_hash_key)
302		{
303			fz_store_hash hash = { NULL };
304			hash.drop = item->val->drop;
305			if (item->type->make_hash_key(ctx, &hash, item->key))
306				fz_hash_remove(ctx, store->hash, &hash);
307		}
308		fz_unlock(ctx, FZ_LOCK_ALLOC);
309		if (drop)
310			item->val->drop(ctx, item->val);
311	
312		/* Always drops the key and drop the item */
313		item->type->drop_key(ctx, item->key);
314		fz_free(ctx, item);
315		fz_lock(ctx, FZ_LOCK_ALLOC);
316	}
317	
318	static size_t
319	ensure_space(fz_context *ctx, size_t tofree)
320	{
321		fz_item *item, *prev;
322		size_t count;
323		fz_store *store = ctx->store;
324		fz_item *to_be_freed = NULL;
325	
326		fz_assert_lock_held(ctx, FZ_LOCK_ALLOC);
327	
328		/* First check that we *can* free tofree; if not, we'd rather not
329		 * cache this. */
330		count = 0;
331		for (item = store->tail; item; item = item->prev)
332		{
333			if (item->val->refs == 1)
334			{
335				count += item->size;
336				if (count >= tofree)
337					break;
338			}
339		}
340	
341		/* If we ran out of items to search, then we can never free enough */
342		if (item == NULL)
343		{
344			return 0;
345		}
346	
347		/* Now move all the items to be freed onto 'to_be_freed' */
348		count = 0;
349		for (item = store->tail; item; item = prev)
350		{
351			prev = item->prev;
352			if (item->val->refs != 1)
353				continue;
354	
355			store->size -= item->size;
356	
357			/* Unlink from the linked list */
358			if (item->next)
359				item->next->prev = item->prev;
360			else
361				store->tail = item->prev;
362			if (item->prev)
363				item->prev->next = item->next;
364			else
365				store->head = item->next;
366	
367			/* Remove from the hash table */
368			if (item->type->make_hash_key)
369			{
370				fz_store_hash hash = { NULL };
371				hash.drop = item->val->drop;
372				if (item->type->make_hash_key(ctx, &hash, item->key))
373					fz_hash_remove(ctx, store->hash, &hash);
374			}
375	
376			/* Link into to_be_freed */
377			item->next = to_be_freed;
378			to_be_freed = item;
379	
380			count += item->size;
381			if (count >= tofree)
382				break;
383		}
384	
385		/* Now we can safely drop the lock and free our pending items. These
386		 * have all been removed from both the store list, and the hash table,
387		 * so they can't be 'found' by anyone else in the meantime. */
388	
389		while (to_be_freed)
390		{
391			int drop;
392	
393			item = to_be_freed;
394			to_be_freed = to_be_freed->next;
395	
396			/* Drop a reference to the value (freeing if required) */
397			if (item->val->refs > 0)
398				(void)Memento_dropRef(item->val);
399			drop = (item->val->refs > 0 && --item->val->refs == 0);
400	
401			fz_unlock(ctx, FZ_LOCK_ALLOC);
402			if (drop)
403				item->val->drop(ctx, item->val);
404	
405			/* Always drops the key and drop the item */
406			item->type->drop_key(ctx, item->key);
407			fz_free(ctx, item);
408			fz_lock(ctx, FZ_LOCK_ALLOC);
409		}
410	
411		return count;
412	}
413	
414	static void
415	touch(fz_store *store, fz_item *item)
416	{
417		if (item->next != item)
418		{
419			/* Already in the list - unlink it */
420			if (item->next)
421				item->next->prev = item->prev;
422			else
423				store->tail = item->prev;
424			if (item->prev)
425				item->prev->next = item->next;
426			else
427				store->head = item->next;
428		}
429		/* Now relink it at the start of the LRU chain */
430		item->next = store->head;
431		if (item->next)
432			item->next->prev = item;
433		else
434			store->tail = item;
435		store->head = item;
436		item->prev = NULL;
437	}
438	
439	void *
440	fz_store_item(fz_context *ctx, void *key, void *val_, size_t itemsize, const fz_store_type *type)
441	{
442		fz_item *item = NULL;
443		size_t size;
444		fz_storable *val = (fz_storable *)val_;
445		fz_store *store = ctx->store;
446		fz_store_hash hash = { NULL };
447		int use_hash = 0;
448	
449		if (!store)
450			return NULL;
451	
452		/* If we fail for any reason, we swallow the exception and continue.
453		 * All that the above program will see is that we failed to store
454		 * the item. */
455	
456		item = Memento_label(fz_malloc_no_throw(ctx, sizeof (fz_item)), "fz_item");
457		if (!item)
458			return NULL;
459		memset(item, 0, sizeof (fz_item));
460	
461		if (type->make_hash_key)
462		{
463			hash.drop = val->drop;
464			use_hash = type->make_hash_key(ctx, &hash, key);
465		}
466	
467		type->keep_key(ctx, key);
468		fz_lock(ctx, FZ_LOCK_ALLOC);
469	
470		/* Fill out the item. To start with, we always set item->next == item
471		 * and item->prev == item. This is so that we can spot items that have
472		 * been put into the hash table without having made it into the linked
473		 * list yet. */
474		item->key = key;
475		item->val = val;
476		item->size = itemsize;
477		item->next = item;
478		item->prev = item;
479		item->type = type;
480	
481		/* If we can index it fast, put it into the hash table. This serves
482		 * to check whether we have one there already. */
483		if (use_hash)
484		{
485			fz_item *existing = NULL;
486	
487			fz_try(ctx)
488			{
489				/* May drop and retake the lock */
490				existing = fz_hash_insert(ctx, store->hash, &hash, item);
491			}
492			fz_catch(ctx)
493			{
494				/* Any error here means that item never made it into the
495				 * hash - so no one else can have a reference. */
496				fz_unlock(ctx, FZ_LOCK_ALLOC);
497				fz_free(ctx, item);
498				type->drop_key(ctx, key);
499				return NULL;
500			}
501			if (existing)
502			{
503				/* There was one there already! Take a new reference
504				 * to the existing one, and drop our current one. */
505				fz_warn(ctx, "found duplicate %s in the store", type->name);
506				touch(store, existing);
507				if (existing->val->refs > 0)
508				{
509					(void)Memento_takeRef(existing->val);
510					existing->val->refs++;
511				}
512				fz_unlock(ctx, FZ_LOCK_ALLOC);
513				fz_free(ctx, item);
514				type->drop_key(ctx, key);
515				return existing->val;
516			}
517		}
518	
519		/* Now bump the ref */
520		if (val->refs > 0)
521		{
522			(void)Memento_takeRef(val);
523			val->refs++;
524		}
525	
526		/* If we haven't got an infinite store, check for space within it */
527		if (store->max != FZ_STORE_UNLIMITED)
528		{
529			/* FIXME: Overflow? */
530			size = store->size + itemsize;
531			if (size > store->max)
532			{
533				FZ_LOG_STORE(ctx, "Store size exceeded: item=%zu, size=%zu, max=%zu\n",
534					itemsize, store->size, store->max);
535				while (size > store->max)
536				{
537					size_t saved;
538	
539					/* First, do any outstanding reaping, even if defer_reap_count > 0 */
540					if (store->needs_reaping)
541					{
542						do_reap(ctx); /* Drops alloc lock */
543						fz_lock(ctx, FZ_LOCK_ALLOC);
544					}
545					size = store->size + itemsize;
546					if (size <= store->max)
547						break;
548	
549					/* ensure_space may drop, then retake the lock */
550					saved = ensure_space(ctx, size - store->max);
551					size -= saved;
552					if (saved == 0)
553					{
554						/* Failed to free any space. */
555						/* We used to 'unstore' it here, but that's wrong.
556						 * If we've already spent the memory to malloc it
557						 * then not putting it in the store just means that
558						 * a resource used multiple times will just be malloced
559						 * again. Better to put it in the store, have the
560						 * store account for it, and for it to potentially be reused.
561						 * When the caller drops the reference to it, it can then
562						 * be dropped from the store on the next attempt to store
563						 * anything else. */
564						break;
565					}
566				}
567				FZ_LOG_DUMP_STORE(ctx, "After eviction:\n");
568			}
569		}
570		store->size += itemsize;
571	
572		/* Regardless of whether it's indexed, it goes into the linked list */
573		touch(store, item);
574		fz_unlock(ctx, FZ_LOCK_ALLOC);
575	
576		return NULL;
577	}
578	
579	void *
580	fz_find_item(fz_context *ctx, fz_store_drop_fn *drop, void *key, const fz_store_type *type)
581	{
582		fz_item *item;
583		fz_store *store = ctx->store;
584		fz_store_hash hash = { NULL };
585		int use_hash = 0;
586	
587		if (!store)
588			return NULL;
589	
590		if (!key)
591			return NULL;
592	
593		if (type->make_hash_key)
594		{
595			hash.drop = drop;
596			use_hash = type->make_hash_key(ctx, &hash, key);
597		}
598	
599		fz_lock(ctx, FZ_LOCK_ALLOC);
600		if (use_hash)
601		{
602			/* We can find objects keyed on indirected objects quickly */
603			item = fz_hash_find(ctx, store->hash, &hash);
604		}
605		else
606		{
607			/* Others we have to hunt for slowly */
608			for (item = store->head; item; item = item->next)
609			{
610				if (item->val->drop == drop && !type->cmp_key(ctx, item->key, key))
611					break;
612			}
613		}
614		if (item)
615		{
616			/* LRU the block. This also serves to ensure that any item
617			 * picked up from the hash before it has made it into the
618			 * linked list does not get whipped out again due to the
619			 * store being full. */
620			touch(store, item);
621			/* And bump the refcount before returning */
622			if (item->val->refs > 0)
623			{
624				(void)Memento_takeRef(item->val);
625				item->val->refs++;
626			}
627			fz_unlock(ctx, FZ_LOCK_ALLOC);
628			return (void *)item->val;
629		}
630		fz_unlock(ctx, FZ_LOCK_ALLOC);
631	
632		return NULL;
633	}
634	
635	void
636	fz_remove_item(fz_context *ctx, fz_store_drop_fn *drop, void *key, const fz_store_type *type)
637	{
638		fz_item *item;
639		fz_store *store = ctx->store;
640		int dodrop;
641		fz_store_hash hash = { NULL };
642		int use_hash = 0;
643	
644		if (type->make_hash_key)
645		{
646			hash.drop = drop;
647			use_hash = type->make_hash_key(ctx, &hash, key);
648		}
649	
650		fz_lock(ctx, FZ_LOCK_ALLOC);
651		if (use_hash)
652		{
653			/* We can find objects keyed on indirect objects quickly */
654			item = fz_hash_find(ctx, store->hash, &hash);
655			if (item)
656				fz_hash_remove(ctx, store->hash, &hash);
657		}
658		else
659		{
660			/* Others we have to hunt for slowly */
661			for (item = store->head; item; item = item->next)
662				if (item->val->drop == drop && !type->cmp_key(ctx, item->key, key))
663					break;
664		}
665		if (item)
666		{
667			/* Momentarily things can be in the hash table without being
668			 * in the list. Don't attempt to unlink these. We indicate
669			 * such items by setting item->next == item. */
670			if (item->next != item)
671			{
672				if (item->next)
673					item->next->prev = item->prev;
674				else
675					store->tail = item->prev;
676				if (item->prev)
677					item->prev->next = item->next;
678				else
679					store->head = item->next;
680			}
681			if (item->val->refs > 0)
682				(void)Memento_dropRef(item->val);
683			dodrop = (item->val->refs > 0 && --item->val->refs == 0);
684			fz_unlock(ctx, FZ_LOCK_ALLOC);
685			if (dodrop)
686				item->val->drop(ctx, item->val);
687			type->drop_key(ctx, item->key);
688			fz_free(ctx, item);
689		}
690		else
691			fz_unlock(ctx, FZ_LOCK_ALLOC);
692	}
693	
694	void
695	fz_empty_store(fz_context *ctx)
696	{
697		fz_store *store = ctx->store;
698	
699		if (store == NULL)
700			return;
701	
702		fz_lock(ctx, FZ_LOCK_ALLOC);
703		/* Run through all the items in the store */
704		while (store->head)
705			evict(ctx, store->head); /* Drops then retakes lock */
706		fz_unlock(ctx, FZ_LOCK_ALLOC);
707	}
