709	fz_store *
710	fz_keep_store_context(fz_context *ctx)
711	{
712		if (ctx == NULL || ctx->store == NULL)
713			return NULL;
714		return fz_keep_imp(ctx, ctx->store, &ctx->store->refs);
715	}
