717	void
718	fz_drop_store_context(fz_context *ctx)
719	{
720		if (!ctx)
721			return;
722		if (fz_drop_imp(ctx, ctx->store, &ctx->store->refs))
723		{
724			fz_empty_store(ctx);
725			fz_drop_hash_table(ctx, ctx->store->hash);
726			fz_free(ctx, ctx->store);
727			ctx->store = NULL;
728		}
729	}
