748	static void
749	fz_debug_store_locked(fz_context *ctx, fz_output *out)
750	{
751		fz_item *item, *next;
752		char buf[256];
753		fz_store *store = ctx->store;
754		size_t list_total = 0;
755	
756		fz_write_printf(ctx, out, "STORE\t-- resource store contents --\n");
757	
758		for (item = store->head; item; item = next)
759		{
760			next = item->next;
761			if (next)
762			{
763				(void)Memento_takeRef(next->val);
764				next->val->refs++;
765			}
766			fz_unlock(ctx, FZ_LOCK_ALLOC);
767			item->type->format_key(ctx, buf, sizeof buf, item->key);
768			fz_lock(ctx, FZ_LOCK_ALLOC);
769			fz_write_printf(ctx, out, "STORE\tstore[*][refs=%d][size=%d] key=%s val=%p\n",
770					item->val->refs, (int)item->size, buf, (void *)item->val);
771			list_total += item->size;
772			if (next)
773			{
774				(void)Memento_dropRef(next->val);
775				next->val->refs--;
776			}
777		}
778	
779		fz_write_printf(ctx, out, "STORE\t-- resource store hash contents --\n");
780		fz_hash_for_each(ctx, store->hash, out, fz_debug_store_item);
781		fz_write_printf(ctx, out, "STORE\t-- end --\n");
782	
783		fz_write_printf(ctx, out, "STORE\tmax=%zu, size=%zu, actual size=%zu\n", store->max, store->size, list_total);
784	}
