793	
794	/*
795		Consider if we have blocks of the following sizes in the store, from oldest
796		to newest:
797	
798		A 32
799		B 64
800		C 128
801		D 256
802	
803		Further suppose we need to free 97 bytes. Naively freeing blocks until we have
804		freed enough would mean we'd free A, B and C, when we could have freed just C.
805	
806		We are forced into an n^2 algorithm by the need to drop the lock as part of the
807		eviction, so we might as well embrace it and go for a solution that properly
808		drops just C.
809	
810		The algorithm used is to scan the list of blocks from oldest to newest, counting
811		how many bytes we can free in the blocks we pass. We stop this scan when we have
812		found enough blocks. We then free the largest block. This releases the lock
813		momentarily, which means we have to start the scan process all over again, so
814		we repeat. This guarantees we only evict a minimum of blocks, but does mean we
815		scan more blocks than we'd ideally like.
816	 */
817	static int
818	scavenge(fz_context *ctx, size_t tofree)
819	{
820		fz_store *store = ctx->store;
821		size_t freed = 0;
822		fz_item *item;
823	
824		if (store->scavenging)
825			return 0;
826	
827		store->scavenging = 1;
828	
829		do
830		{
831			/* Count through a suffix of objects in the store until
832			 * we find enough to give us what we need to evict. */
833			size_t suffix_size = 0;
834			fz_item *largest = NULL;
835	
836			for (item = store->tail; item; item = item->prev)
837			{
838				if (item->val->refs == 1 && (item->val->droppable == NULL || item->val->droppable(ctx, item->val)))
839				{
840					/* This one is evictable */
841					suffix_size += item->size;
842					if (largest == NULL || item->size > largest->size)
843						largest = item;
844					if (suffix_size >= tofree - freed)
845						break;
846				}
847			}
848	
849			/* If there are no evictable blocks, we can't find anything to free. */
850			if (largest == NULL)
851				break;
852	
853			/* Free largest. */
854			if (freed == 0) {
855				FZ_LOG_DUMP_STORE(ctx, "Before scavenge:\n");
856			}
857			freed += largest->size;
858			evict(ctx, largest); /* Drops then retakes lock */
859		}
860		while (freed < tofree);
861	
862		if (freed != 0) {
863			FZ_LOG_DUMP_STORE(ctx, "After scavenge:\n");
864		}
865		store->scavenging = 0;
866		/* Success is managing to evict any blocks */
867		return freed != 0;
868	}
869	
870	void
871	fz_drop_storable(fz_context *ctx, const fz_storable *sc)
872	{
873		/* Explicitly drop const to allow us to use const
874		 * sanely throughout the code. */
875		fz_storable *s = (fz_storable *)sc;
876		int num;
877	
878		if (s == NULL)
879			return;
880	
881		fz_lock(ctx, FZ_LOCK_ALLOC);
882		/* Drop the ref, and leave num as being the number of
883		 * refs left (-1 meaning, "statically allocated"). */
884		if (s->refs > 0)
885		{
886			(void)Memento_dropIntRef(s);
887			num = --s->refs;
888		}
889		else
890			num = -1;
891	
892		/* If we have just 1 ref left, it's possible that
893		 * this ref is held by the store. If the store is
894		 * oversized, we ought to throw any such references
895		 * away to try to bring the store down to a "legal"
896		 * size. Run a scavenge to check for this case. */
897		if (ctx->store->max != FZ_STORE_UNLIMITED)
898			if (num == 1 && ctx->store->size > ctx->store->max)
899				scavenge(ctx, ctx->store->size - ctx->store->max);
900		fz_unlock(ctx, FZ_LOCK_ALLOC);
901	
902		/* If we have no references to an object left, then
903		 * it cannot possibly be in the store (as the store always
904		 * keeps a ref to everything in it, and doesn't drop via
905		 * this method). So we can simply drop the storable object
906		 * itself without any operations on the fz_store.
907		 */
908		if (num == 0)
909			s->drop(ctx, s);
910	}
