912	int fz_store_scavenge_external(fz_context *ctx, size_t size, int *phase)
913	{
914		int ret;
915	
916		fz_lock(ctx, FZ_LOCK_ALLOC);
917		ret = fz_store_scavenge(ctx, size, phase);
918		fz_unlock(ctx, FZ_LOCK_ALLOC);
919	
920		return ret;
921	}
922	
923	int fz_store_scavenge(fz_context *ctx, size_t size, int *phase)
924	{
925		fz_store *store;
926		size_t max;
927	
928		store = ctx->store;
929		if (store == NULL)
930			return 0;
931	
932	#ifdef DEBUG_SCAVENGING
933		fz_write_printf(ctx, fz_stdout(ctx), "Scavenging: store=%zu size=%zu phase=%d\n", store->size, size, *phase);
934		fz_debug_store_locked(ctx, fz_stdout(ctx));
935		Memento_stats();
936	#endif
937		do
938		{
939			size_t tofree;
940	
941			/* Calculate 'max' as the maximum size of the store for this phase */
942			if (*phase >= 16)
943				max = 0;
944			else if (store->max != FZ_STORE_UNLIMITED)
945				max = store->max / 16 * (16 - *phase);
946			else
947				max = store->size / (16 - *phase) * (15 - *phase);
948			(*phase)++;
949	
950			/* Slightly baroque calculations to avoid overflow */
951			if (size > SIZE_MAX - store->size)
952				tofree = SIZE_MAX - max;
953			else if (size + store->size > max)
954				continue;
955			else
956				tofree = size + store->size - max;
957	
958			if (scavenge(ctx, tofree))
959			{
960	#ifdef DEBUG_SCAVENGING
961				fz_write_printf(ctx, fz_stdout(ctx), "scavenged: store=%zu\n", store->size);
962				fz_debug_store(ctx, fz_stdout(ctx));
963				Memento_stats();
964	#endif
965				return 1;
966			}
967		}
968		while (max > 0);
969	
970	#ifdef DEBUG_SCAVENGING
971		fz_write_printf(ctx, fz_stdout(ctx), "scavenging failed\n");
972		fz_debug_store(ctx, fz_stdout(ctx));
973		Memento_listBlocks();
974	#endif
975		return 0;
976	}
977	
978	int
979	fz_shrink_store(fz_context *ctx, unsigned int percent)
980	{
981		int success;
982		fz_store *store;
983		size_t new_size;
984	
985		if (percent >= 100)
986			return 1;
987	
988		store = ctx->store;
989		if (store == NULL)
990			return 0;
991	
992	#ifdef DEBUG_SCAVENGING
993		fz_write_printf(ctx, fz_stdout(ctx), "fz_shrink_store: %zu\n", store->size/(1024*1024));
994	#endif
995		fz_lock(ctx, FZ_LOCK_ALLOC);
996	
997		if (store->max == FZ_STORE_UNLIMITED)
998			new_size = (size_t)(((uint64_t)store->size * percent) / 100);
999		else
1000			new_size = (size_t)(((uint64_t)store->max * percent) / 100);
1001	
1002		if (store->size > new_size)
1003			scavenge(ctx, store->size - new_size);
1004	
1005		success = (store->size <= new_size) ? 1 : 0;
1006		fz_unlock(ctx, FZ_LOCK_ALLOC);
1007	#ifdef DEBUG_SCAVENGING
1008		fz_write_printf(ctx, fz_stdout(ctx), "fz_shrink_store after: %zu\n", store->size/(1024*1024));
1009	#endif
1010	
1011		return success;
1012	}
1013	
1014	void fz_filter_store(fz_context *ctx, fz_store_filter_fn *fn, void *arg, const fz_store_type *type)
1015	{
1016		fz_store *store;
1017		fz_item *item, *prev, *remove;
1018	
1019		store = ctx->store;
1020		if (store == NULL)
1021			return;
1022	
1023		fz_lock(ctx, FZ_LOCK_ALLOC);
1024	
1025		/* Filter the items */
1026		remove = NULL;
1027		for (item = store->tail; item; item = prev)
1028		{
1029			prev = item->prev;
1030			if (item->type != type)
1031				continue;
1032	
1033			if (fn(ctx, arg, item->key) == 0)
1034				continue;
1035	
1036			/* We have to drop it */
1037			store->size -= item->size;
1038	
1039			/* Unlink from the linked list */
1040			if (item->next)
1041				item->next->prev = item->prev;
1042			else
1043				store->tail = item->prev;
1044			if (item->prev)
1045				item->prev->next = item->next;
1046			else
1047				store->head = item->next;
1048	
1049			/* Remove from the hash table */
1050			if (item->type->make_hash_key)
1051			{
1052				fz_store_hash hash = { NULL };
1053				hash.drop = item->val->drop;
1054				if (item->type->make_hash_key(ctx, &hash, item->key))
1055					fz_hash_remove(ctx, store->hash, &hash);
1056			}
1057	
1058			/* Store whether to drop this value or not in 'prev' */
1059			if (item->val->refs > 0)
1060				(void)Memento_dropRef(item->val);
1061			item->prev = (item->val->refs > 0 && --item->val->refs == 0) ? item : NULL;
1062	
1063			/* Store it in our removal chain - just singly linked */
1064			item->next = remove;
1065			remove = item;
1066		}
1067		fz_unlock(ctx, FZ_LOCK_ALLOC);
1068	
1069		/* Now drop the remove chain */
1070		for (item = remove; item != NULL; item = remove)
1071		{
1072			remove = item->next;
1073	
1074			/* Drop a reference to the value (freeing if required) */
1075			if (item->prev) /* See above for our abuse of prev here */
1076				item->val->drop(ctx, item->val);
1077	
1078			/* Always drops the key and drop the item */
1079			item->type->drop_key(ctx, item->key);
1080			fz_free(ctx, item);
1081		}
1082	}
1083	
1084	void fz_defer_reap_start(fz_context *ctx)
1085	{
1086		if (ctx->store == NULL)
1087			return;
1088	
1089		fz_lock(ctx, FZ_LOCK_ALLOC);
1090		ctx->store->defer_reap_count++;
1091		fz_unlock(ctx, FZ_LOCK_ALLOC);
1092	}
1093	
1094	void fz_defer_reap_end(fz_context *ctx)
1095	{
1096		int reap;
1097	
1098		if (ctx->store == NULL)
1099			return;
1100	
1101		fz_lock(ctx, FZ_LOCK_ALLOC);
1102		--ctx->store->defer_reap_count;
1103		reap = ctx->store->defer_reap_count == 0 && ctx->store->needs_reaping;
1104		if (reap)
1105			do_reap(ctx); /* Drops FZ_LOCK_ALLOC */
1106		else
1107			fz_unlock(ctx, FZ_LOCK_ALLOC);
1108	}
1109	
1110	#ifdef ENABLE_STORE_LOGGING
1111	
1112	void fz_log_dump_store(fz_context *ctx, const char *fmt, ...)
1113	{
1114		fz_output *out;
1115		va_list args;
1116		va_start(args, fmt);
1117		out = fz_new_log_for_module(ctx, "STORE");
1118		fz_write_vprintf(ctx, out, fmt, args);
1119		va_end(args);
1120		fz_debug_store(ctx, out);
1121		fz_write_printf(ctx, out, "STORE\tEND\n");
1122		fz_close_output(ctx, out);
1123		fz_drop_output(ctx, out);
1124	}
1125	
1126	#endif
